    "id": "cs-74-marketplace-fraud",
    "title": "Counterfeit Spike on the Marketplace: Stop the Bleeding Before Q4",
    "cluster": "ecommerce_marketplace",
    "duration": "medium",
    "estimatedMinutes": 45,
